// src/App.js

import './index.css';
import React, { useState } from 'react';
import Header from "./components/Header";
import Sidebar from './components/Sidebar';
import TelaPeriodos from "./components/TelaPeriodos";
import TelaAlunos from "./components/TelaAlunos";
import TelaPacientes from "./components/TelaPacientes";
import TelaDisciplinas from "./components/TelaDisciplinas";
import TelaAgendamentos from "./components/TelaAgendamentos";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import Login from "./Login";
import DashboardAluno from "./DashboardAluno";
import DashboardRecepcao from "./DashboardRecepcao";
import BottomNavBar from './components/BottomNavBar';
import { AuthProvider, useAuth } from './context/AuthContext'; // Importa o provider e o hook
import ProtectedRoute from './components/ProtectedRoute';

// Componente que decide qual dashboard exibir, de acordo com o role do usuário
function Dashboards() {
  const { user } = useAuth();
  if (user?.role === "recepcao") return <DashboardRecepcao />;
  return <DashboardAluno />;
}

// Layout interno que exibe Header, Sidebar e o conteúdo principal
function LayoutInterno() {
  const [active, setActive] = useState('dashboard');

  function renderConteudo() {
    switch (active) {
      // Quando active === 'dashboard', renderizamos o componente Dashboards()
      case 'dashboard':
        return <Dashboards />; 

      case 'agendar':
        return <TelaAgendamentos />;
      case 'disciplinas':
        return <TelaDisciplinas />;
      case 'pacientes':
        return <TelaPacientes />;
      case 'alunos':
        return <TelaAlunos />;
      case 'periodos':
        return <TelaPeriodos />;

      default:
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Página não encontrada</h1>
          </div>
        );
    }
  }

  return (
    <div className="bg-[#ffffff] min-h-screen">
      <Header />
      <div className="flex">
        {/* Apenas em telas md+ mostramos a Sidebar */}
        <div className="hidden md:block">
          <Sidebar active={active} onMenuClick={setActive} />
        </div>
        <main className="flex-1 ml-0 md:ml-64 mt-16 p-8 h-[calc(100vh-64px)] overflow-y-auto">
          <div className="mx-auto">{renderConteudo()}</div>
        </main>
      </div>
      {/* BottomNavBar só aparece no mobile */}
      <BottomNavBar active={active} onMenuClick={setActive} />
    </div>
  );
}

// Componente principal da aplicação
export default function App() {
  return (
    // AuthProvider fica no topo da árvore para fornecer contexto de login/logout
    <AuthProvider>
      <Router>
        <Routes>
          {/* Rota de Login (pública) */}
          <Route path="/login" element={<Login />} />

          {/* Todas as demais rotas ficarão protegidas */}
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />

          {/* Qualquer outro caminho redireciona para /login */}
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}
